1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	}
8	
9	const PROCESSING_FEE = 5;
10	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
11	
12	const BASE_PRICES: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	};
19	
20	const COMPONENT_TYPES = new Set(["rune"]);
21	const BLOCK_PRICE: Record<string, number> = {
22	  rune: 60,
23	};
24	
25	export function quote(_customer: Customer, items: Item[]): number {
26	  let total = 0;
27	  const componentCounts: Record<string, number> = {};
28	  for (const item of items) {
29	    if (COMPONENT_TYPES.has(item.type)) {
30	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
31	      continue;
32	    }
33	    const base = BASE_PRICES[item.type] ?? 0;
34	    total += base + base * FIRST_INSURANCE_SURCHARGE_RATE;
35	  }
36	  for (const type of Object.keys(componentCounts)) {
37	    const count = componentCounts[type];
38	    const unitPrice = BASE_PRICES[type] ?? 0;
39	    const base = count === 3 ? BLOCK_PRICE[type] : unitPrice * count;
40	    total += base + base * FIRST_INSURANCE_SURCHARGE_RATE;
41	  }
42	  total += PROCESSING_FEE;
43	  return Math.ceil(total);
44	}
45	
46	export function claim(): unknown {
47	  return undefined;
48	}
